#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e6+5;
int a[MAXN];
void solve()
{
	int n=read();
    for(int i=1;i<=n;++i)
    {
        a[i]=read();
    }
	ll ans=0;
	int l=1,r;
	while(l<=n)
    {
		if(a[l]==l)
        {
			++l;
			continue;
		}
		int maxx=a[l];
		r=l+1;
		maxx=max(maxx,a[r]);
		while(maxx>r)
        {
			++r;
			maxx=max(maxx,a[r]);
		}
		ans+=r-l+1;
		l=r+1;
	}
    write(ans);
	return ;
}
int main(void)
{
    for(int t=read();t;--t)
    {
        solve();
        puts("");
    }
	return false;
}
